import { useState, useEffect, useCallback, useRef } from "react";
import { useNavigate } from "react-router-dom";
import { useAuth } from "../../context/AuthContext";
import API from "../../api";

/**
 * UI STYLE TOKENS (keeps code long + consistent)
 */
const ui = {
  radius: 14,
  radiusSm: 10,
  shadowSoft: "0 4px 20px rgba(0,0,0,0.06)",
  shadowHover: "0 8px 28px rgba(0,0,0,0.12)",
  glass: "rgba(255,255,255,0.6)",
  blur: "blur(10px)",
  transition: "all 0.25s ease",
};

export default function WaiterPanel() {
  const [tables, setTables] = useState([]);
  const [menu, setMenu] = useState([]);
  const [specials, setSpecials] = useState({});
  const [selectedTable, setSelectedTable] = useState(null);
  const [allRounds, setAllRounds] = useState([]);
  const [draftRoundIdx, setDraftRoundIdx] = useState(null);
  const [loading, setLoading] = useState(true);
  const [roundLoading, setRoundLoading] = useState(false);
  const [view, setView] = useState("tables");
  const [confirmModal, setConfirmModal] = useState(false);
  const [confirming, setConfirming] = useState(false);
  const [activeOrderType, setActiveOrderType] = useState("table");
  const [taxSettings, setTaxSettings] = useState(null);

  const { user, logout, theme, toggleTheme } = useAuth();
  const navigate = useNavigate();
  const summaryRef = useRef(null);

  /**
   * LOAD INITIAL DATA
   */
  const loadData = useCallback(async () => {
    try {
      const [t, m, s, tax] = await Promise.all([
        API.get("/tables"),
        API.get("/menu"),
        API.get("/extras/specials"),
        API.get("/extras/tax-settings"),
      ]);

      setTables(t.data);
      setMenu(m.data.filter(i => i.is_available));

      const sMap = {};
      s.data.forEach(sp => {
        sMap[sp.menu_id] = {
          ...sp,
          discounted_price:
            sp.discount_pct > 0
              ? Math.round(sp.price * (1 - sp.discount_pct / 100))
              : sp.price,
        };
      });

      setSpecials(sMap);
      setTaxSettings(tax.data);
    } catch (e) {
      console.error(e);
    }

    setLoading(false);
  }, []);

  useEffect(() => {
    loadData();
  }, [loadData]);

  /**
   * LOAD TABLE ROUNDS
   */
  const loadTableRounds = useCallback(async (table) => {
    setRoundLoading(true);
    try {
      const res = await API.get(`/orders/table/${table.id}/all`);
      const orders = res.data || [];

      if (!orders.length) {
        setAllRounds([]);
        setDraftRoundIdx(null);
        return;
      }

      const rounds = await Promise.all(
        orders.map(async (order, idx) => {
          try {
            const detail = await API.get(`/orders/${order.id}`);
            return {
              order: detail.data.order,
              items: detail.data.items || [],
              roundNumber: idx + 1,
            };
          } catch {
            return { order, items: [], roundNumber: idx + 1 };
          }
        })
      );

      setAllRounds(rounds);

      const draftIdx = rounds.findIndex(r => r.order.status === "draft");
      setDraftRoundIdx(draftIdx === -1 ? null : draftIdx);
    } catch (e) {
      console.error(e);
    }
    setRoundLoading(false);
  }, []);

  /**
   * ACTIONS
   */
  const selectTable = async (table) => {
    setSelectedTable(table);
    setActiveOrderType("table");
    setView("order");
    await loadTableRounds(table);
  };

  const startTakeaway = async () => {
    setRoundLoading(true);
    try {
      const res = await API.post("/orders", { order_type: "takeaway" });
      setAllRounds([{ order: res.data, items: [], roundNumber: 1 }]);
      setDraftRoundIdx(0);
      setSelectedTable(null);
      setActiveOrderType("takeaway");
      setView("order");
    } catch {}
    setRoundLoading(false);
  };

  const startOrder = async () => {
    if (!selectedTable) return;
    setRoundLoading(true);

    try {
      const res = await API.post("/orders", {
        table_id: selectedTable.id,
        order_type: "table",
      });

      setAllRounds([{ order: res.data, items: [], roundNumber: 1 }]);
      setDraftRoundIdx(0);
    } catch (err) {
      if (err.response?.data?.order_id) {
        await loadTableRounds(selectedTable);
      }
    }

    setRoundLoading(false);
  };

  const addItem = async (menuItem) => {
    if (draftRoundIdx === null) return;

    const round = allRounds[draftRoundIdx];
    if (!round || round.order.status !== "draft") return;

    const special = specials[menuItem.id];
    const unit_price = special ? special.discounted_price : menuItem.price;

    try {
      await API.post(`/orders/${round.order.id}/items`, {
        menu_id: menuItem.id,
        quantity: 1,
        unit_price,
      });
      await refreshRound(draftRoundIdx);
    } catch {}
  };

  const refreshRound = async (idx) => {
    const round = allRounds[idx];
    if (!round) return;

    try {
      const res = await API.get(`/orders/${round.order.id}`);
      setAllRounds(prev => {
        const updated = [...prev];
        updated[idx] = {
          ...updated[idx],
          order: res.data.order,
          items: res.data.items || [],
        };
        return updated;
      });
    } catch {}
  };

  const handleSendToKitchen = async () => {
    if (draftRoundIdx === null) return;

    const round = allRounds[draftRoundIdx];
    if (!round || !round.items.length) return;

    setConfirming(true);

    try {
      await API.put(`/orders/${round.order.id}/confirm`);
      await refreshRound(draftRoundIdx);
      setDraftRoundIdx(null);
      setConfirmModal(false);
      await loadData();
    } catch {}

    setConfirming(false);
  };

  const goBack = () => {
    setView("tables");
    setAllRounds([]);
    setDraftRoundIdx(null);
    setSelectedTable(null);
    loadData();
  };

  /**
   * COMPUTED VALUES
   */
  const categories = [...new Set(menu.map(m => m.category))];
  const combinedTotal = allRounds.reduce(
    (sum, r) => sum + Number(r.order?.total || 0),
    0
  );

  const taxRate = taxSettings?.tax_rate || 13;
  const taxEnabled = taxSettings?.tax_enabled !== false;

  const taxAmount = taxEnabled
    ? (combinedTotal * taxRate) / 100
    : 0;

  const grandTotal = combinedTotal + taxAmount;

  /**
   * RENDER
   */
  return (
    <div style={{
      minHeight: "100vh",
      background: "linear-gradient(180deg,#f8fafc,#eef2ff)",
      display: "flex",
      flexDirection: "column"
    }}>

      {/* HEADER */}
      <header style={{
        padding: "14px 28px",
        display: "flex",
        justifyContent: "space-between",
        alignItems: "center",
        backdropFilter: ui.blur,
        background: "rgba(255,255,255,0.7)",
        borderBottom: "1px solid rgba(0,0,0,0.05)",
        position: "sticky",
        top: 0,
        zIndex: 20
      }}>
        <div style={{ display: "flex", alignItems: "center", gap: 14 }}>
          <div style={{
            width: 42,
            height: 42,
            borderRadius: 12,
            background: "linear-gradient(135deg,#6366f1,#8b5cf6)",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            color: "#fff",
            fontSize: 20,
            fontWeight: 700
          }}>
            🍽️
          </div>

          <div>
            <div style={{ fontWeight: 800 }}>Waiter Panel</div>
            <div style={{ fontSize: 12, opacity: 0.6 }}>
              {user?.restaurant_name}
            </div>
          </div>
        </div>

        <div style={{ display: "flex", gap: 10 }}>
          {view === "order" && (
            <button className="btn btn-secondary" onClick={goBack}>
              ← Tables
            </button>
          )}

          <button className="btn btn-ghost" onClick={toggleTheme}>
            {theme === "dark" ? "🌙" : "☀️"}
          </button>

          <button className="btn btn-ghost" onClick={() => {
            logout();
            navigate("/");
          }}>
            🚪
          </button>
        </div>
      </header>

      {/* MAIN */}
      <div style={{ flex: 1, padding: 24 }}>

        {view === "tables" && (
          <>
            {/* ACTION BAR */}
            <div style={{
              display: "flex",
              justifyContent: "space-between",
              marginBottom: 20
            }}>
              <h2>Tables</h2>

              <button
                onClick={startTakeaway}
                style={{
                  background: "linear-gradient(135deg,#f59e0b,#d97706)",
                  color: "#fff",
                  border: "none",
                  padding: "10px 16px",
                  borderRadius: 10,
                  fontWeight: 700,
                  cursor: "pointer",
                  boxShadow: ui.shadowSoft
                }}
              >
                📦 Takeaway
              </button>
            </div>

            {/* TABLE GRID */}
            <div style={{
              display: "grid",
              gridTemplateColumns: "repeat(auto-fill,minmax(150px,1fr))",
              gap: 16
            }}>
              {tables.map(t => (
                <div
                  key={t.id}
                  onClick={() => selectTable(t)}
                  style={{
                    padding: 18,
                    borderRadius: ui.radius,
                    background: "#fff",
                    boxShadow: ui.shadowSoft,
                    cursor: "pointer",
                    transition: ui.transition
                  }}
                  onMouseEnter={e => {
                    e.currentTarget.style.transform = "translateY(-4px)";
                    e.currentTarget.style.boxShadow = ui.shadowHover;
                  }}
                  onMouseLeave={e => {
                    e.currentTarget.style.transform = "none";
                    e.currentTarget.style.boxShadow = ui.shadowSoft;
                  }}
                >
                  <div style={{
                    fontSize: 22,
                    fontWeight: 800
                  }}>
                    T{t.table_number}
                  </div>

                  <div style={{
                    fontSize: 12,
                    opacity: 0.6
                  }}>
                    {t.status}
                  </div>
                </div>
              ))}
            </div>
          </>
        )}

        {/* ORDER VIEW */}
        {view === "order" && (
          <div style={{
            display: "grid",
            gridTemplateColumns: "1fr 380px",
            gap: 20
          }}>

            {/* MENU */}
            <div>
              {categories.map(cat => (
                <div key={cat} style={{ marginBottom: 24 }}>
                  <h4 style={{ marginBottom: 10 }}>{cat}</h4>

                  <div style={{
                    display: "grid",
                    gridTemplateColumns: "repeat(auto-fill,minmax(160px,1fr))",
                    gap: 12
                  }}>
                    {menu
                      .filter(m => m.category === cat)
                      .map(item => (
                        <button
                          key={item.id}
                          onClick={() => addItem(item)}
                          style={{
                            padding: 14,
                            borderRadius: ui.radiusSm,
                            background: "#fff",
                            border: "1px solid #eee",
                            textAlign: "left",
                            cursor: "pointer",
                            transition: ui.transition
                          }}
                        >
                          <div style={{ fontWeight: 600 }}>
                            {item.name}
                          </div>
                          <div style={{
                            color: "#16a34a",
                            fontWeight: 700
                          }}>
                            Rs. {item.price}
                          </div>
                        </button>
                      ))}
                  </div>
                </div>
              ))}
            </div>

            {/* SUMMARY */}
            <div style={{
              background: "#fff",
              borderRadius: ui.radius,
              padding: 18,
              boxShadow: ui.shadowSoft,
              position: "sticky",
              top: 90
            }}>
              <h3>Summary</h3>

              <div style={{
                maxHeight: 400,
                overflow: "auto"
              }}>
                {allRounds.map((r, idx) => (
                  <div key={idx} style={{
                    borderBottom: "1px solid #eee",
                    padding: "8px 0"
                  }}>
                    <strong>Round {idx + 1}</strong>

                    {r.items.map(i => (
                      <div key={i.id} style={{
                        display: "flex",
                        justifyContent: "space-between",
                        fontSize: 13
                      }}>
                        <span>{i.name} ×{i.quantity}</span>
                        <span>Rs. {i.price}</span>
                      </div>
                    ))}
                  </div>
                ))}
              </div>

              {/* TOTAL */}
              <div style={{ marginTop: 12 }}>
                <div style={{
                  display: "flex",
                  justifyContent: "space-between"
                }}>
                  <span>Subtotal</span>
                  <span>Rs. {combinedTotal}</span>
                </div>

                {taxEnabled && (
                  <div style={{
                    display: "flex",
                    justifyContent: "space-between"
                  }}>
                    <span>VAT</span>
                    <span>Rs. {taxAmount}</span>
                  </div>
                )}

                <div style={{
                  display: "flex",
                  justifyContent: "space-between",
                  fontWeight: 800,
                  fontSize: 18,
                  marginTop: 8
                }}>
                  <span>Total</span>
                  <span>Rs. {grandTotal}</span>
                </div>
              </div>

              {/* SEND BUTTON */}
              {draftRoundIdx !== null && (
                <button
                  onClick={() => setConfirmModal(true)}
                  style={{
                    marginTop: 14,
                    width: "100%",
                    padding: "12px 0",
                    borderRadius: 10,
                    border: "none",
                    color: "#fff",
                    fontWeight: 800,
                    background: "linear-gradient(135deg,#6366f1,#8b5cf6)",
                    cursor: "pointer"
                  }}
                >
                  🚀 Send to Kitchen
                </button>
              )}
            </div>
          </div>
        )}
      </div>

      {/* MODAL */}
      {confirmModal && (
        <div className="modal-overlay">
          <div className="modal">
            <h3>Confirm Order</h3>

            <button
              onClick={handleSendToKitchen}
              disabled={confirming}
              className="btn btn-primary"
            >
              {confirming ? "Sending..." : "Confirm"}
            </button>
          </div>
        </div>
      )}
    </div>
  );
}
